class Solution:
    def featureExtraction(self, docs):
        # 记录每个字母在所有片段中的最小出现次数
        min_cnt = [10 ** 9] * 26

        # 逐个片段统计字母频次
        for s in docs:
            cnt = [0] * 26
            for ch in s:
                cnt[ord(ch) - ord('a')] += 1

            # 更新全局最小值
            for i in range(26):
                if cnt[i] < min_cnt[i]:
                    min_cnt[i] = cnt[i]

        # 按字典序构造答案
        ans = []
        for i in range(26):
            if min_cnt[i] > 0:
                ans.append(chr(ord('a') + i) * min_cnt[i])

        # 输出格式要求加双引号
        return '"' + ''.join(ans) + '"'
```

```java
public class Solution {
    public String featureExtraction(String[] docs) {
        // 记录每个字母在所有片段中的最小出现次数
        int[] minCnt = new int[26];
        java.util.Arrays.fill(minCnt, Integer.MAX_VALUE);

        // 逐个片段统计字母频次
        for (String s : docs) {
            int[] cnt = new int[26];
            for (int i = 0; i < s.length(); i++) {
                cnt[s.charAt(i) - 'a']++;
            }

            // 更新全局最小值
            for (int i = 0; i < 26; i++) {
                minCnt[i] = Math.min(minCnt[i], cnt[i]);
            }
        }

        // 按字典序构造答案
        StringBuilder ans = new StringBuilder();
        for (int i = 0; i < 26; i++) {
            for (int j = 0; j < minCnt[i]; j++) {
                ans.append((char) ('a' + i));
            }
        }

        // 输出格式要求加双引号
        return "\"" + ans.toString() + "\"";
    }
}
