class Solution {
public:
    string featureExtraction(vector<string>& docs) {
        // 记录每个字母在所有片段中的最小出现次数
        vector<int> minCnt(26, INT_MAX);

        // 逐个片段统计字母频次
        for (const string& s : docs) {
            vector<int> cnt(26, 0);
            for (char ch : s) {
                cnt[ch - 'a']++;
            }

            // 更新全局最小值
            for (int i = 0; i < 26; i++) {
                minCnt[i] = min(minCnt[i], cnt[i]);
            }
        }

        // 按字典序构造答案
        string ans;
        for (int i = 0; i < 26; i++) {
            ans.append(minCnt[i], char('a' + i));
        }

        // 输出格式要求加双引号
        return "\"" + ans + "\"";
    }
};
