var featureExtraction = function(docs) {
    // 用 Infinity 初始化最小计数
    const minCnt = new Array(26).fill(Infinity);
    // 记录某字母是否在所有片段中都出现
    const present = new Array(26).fill(true);

    // 遍历每个片段
    for (const doc of docs) {
        const cnt = new Array(26).fill(0);
        for (const ch of doc) cnt[ch.charCodeAt(0) - 97]++;
        for (let c = 0; c < 26; c++) {
            if (cnt[c] === 0) present[c] = false;
            else minCnt[c] = Math.min(minCnt[c], cnt[c]);
        }
    }

    // 构造答案字符串
    let result = '';
    for (let c = 0; c < 26; c++) {
        if (present[c]) result += String.fromCharCode(97 + c).repeat(minCnt[c]);
    }

    // 输出格式要求加双引号
    return '"' + result + '"';
};
