```c
#include <stdlib.h>
#include <string.h>
#include <limits.h>

char* featureExtraction(char** docs, int docsSize) {
    int minCnt[26], present[26];

    // 初始化最小计数为最大值，标记为全体出现
    for (int c = 0; c < 26; c++) {
        minCnt[c] = INT_MAX;
        present[c] = 1;
    }

    // 统计每个片段
    for (int i = 0; i < docsSize; i++) {
        int cnt[26] = {0};
        for (int j = 0; docs[i][j]; j++)
            cnt[docs[i][j] - 'a']++;

        // 更新最小计数与存在标记
        for (int c = 0; c < 26; c++) {
            if (cnt[c] == 0)
                present[c] = 0;
            else if (cnt[c] < minCnt[c])
                minCnt[c] = cnt[c];
        }
    }

    // 计算结果长度
    int total = 0;
    for (int c = 0; c < 26; c++)
        if (present[c]) total += minCnt[c];

    // 构建结果字符串
    char* result = (char*)malloc(total + 3); // 多分配2个位置用于双引号和终止符
    int pos = 0;
    result[pos++] = '"'; // 添加左双引号

    for (int c = 0; c < 26; c++) {
        if (present[c]) {
            for (int k = 0; k < minCnt[c]; k++)
                result[pos++] = 'a' + c;
        }
    }

    result[pos++] = '"'; // 添加右双引号
    result[pos] = '\0';  // 字符串结束
    return result;
}
